import{_ as s,b as i,e,al as a}from"./chunks/framework.tsjOpNIE.js";const g=JSON.parse('{"title":"HTML5 增强表单特性 (Enhanced Forms)","description":"","frontmatter":{},"headers":[],"relativePath":"html/enhancedForms.md","filePath":"html/enhancedForms.md","lastUpdated":1772787829000}'),l={name:"html/enhancedForms.md"};function n(d,t,h,o,r,p){return i(),e("div",null,[...t[0]||(t[0]=[a('<h1 id="html5-增强表单特性-enhanced-forms" tabindex="-1">HTML5 增强表单特性 (Enhanced Forms) <a class="header-anchor" href="#html5-增强表单特性-enhanced-forms" aria-label="Permalink to &quot;HTML5 增强表单特性 (Enhanced Forms)&quot;">​</a></h1><p>HTML5 极大地增强了表单的功能。以前需要写大量 JavaScript 才能实现的<strong>验证、输入限制、日期选择</strong>等功能，现在只需要简单的 HTML 属性即可搞定。</p><h2 id="_1-新增输入类型-type-属性" tabindex="-1">1. 新增输入类型 (<code>type</code> 属性) <a class="header-anchor" href="#_1-新增输入类型-type-属性" aria-label="Permalink to &quot;1. 新增输入类型 (`type` 属性)&quot;">​</a></h2><p>HTML5 引入了许多语义化的 <code>type</code> 值。在移动端，这些类型能<strong>自动唤起对应的软键盘</strong>（核心优势）。</p><table tabindex="0"><thead><tr><th style="text-align:left;">类型 (type)</th><th style="text-align:left;">描述</th><th style="text-align:left;">移动端键盘表现</th><th style="text-align:left;">浏览器默认验证</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>email</code></strong></td><td style="text-align:left;">电子邮件</td><td style="text-align:left;">键盘带 <code>@</code> 和 <code>.</code> 符号。</td><td style="text-align:left;">必须包含 <code>@</code>。</td></tr><tr><td style="text-align:left;"><strong><code>tel</code></strong></td><td style="text-align:left;">电话号码</td><td style="text-align:left;">纯数字拨号键盘。</td><td style="text-align:left;"><strong>无</strong>（因为各国电话格式不同）。需配合 <code>pattern</code>。</td></tr><tr><td style="text-align:left;"><strong><code>url</code></strong></td><td style="text-align:left;">网址</td><td style="text-align:left;">键盘带 <code>/</code> 和 <code>.com</code>。</td><td style="text-align:left;">必须是合法 URL 格式。</td></tr><tr><td style="text-align:left;"><strong><code>number</code></strong></td><td style="text-align:left;">数字</td><td style="text-align:left;">数字键盘。</td><td style="text-align:left;">只能输入数字。配合 <code>min</code>, <code>max</code>, <code>step</code> 使用。</td></tr><tr><td style="text-align:left;"><strong><code>search</code></strong></td><td style="text-align:left;">搜索框</td><td style="text-align:left;">键盘回车键变成“搜索”。</td><td style="text-align:left;">输入框右侧可能带个“x”清空按钮。</td></tr><tr><td style="text-align:left;"><strong><code>date</code></strong></td><td style="text-align:left;">日期选择器</td><td style="text-align:left;">唤起系统原生日期滚轮。</td><td style="text-align:left;">显示年/月/日选择器。</td></tr><tr><td style="text-align:left;"><strong><code>time</code></strong></td><td style="text-align:left;">时间选择器</td><td style="text-align:left;">唤起时间滚轮。</td><td style="text-align:left;">显示时:分。</td></tr><tr><td style="text-align:left;"><strong><code>range</code></strong></td><td style="text-align:left;">滑块</td><td style="text-align:left;">-</td><td style="text-align:left;">拖动滑块选择数值。</td></tr><tr><td style="text-align:left;"><strong><code>color</code></strong></td><td style="text-align:left;">颜色选择器</td><td style="text-align:left;">-</td><td style="text-align:left;">弹出取色板。</td></tr><tr><td style="text-align:left;"><strong><code>password</code></strong></td><td style="text-align:left;">密码</td><td style="text-align:left;">-</td><td style="text-align:left;">输入内容掩码显示（圆点）。</td></tr></tbody></table><h2 id="_2-核心增强属性-attributes" tabindex="-1">2. 核心增强属性 (Attributes) <a class="header-anchor" href="#_2-核心增强属性-attributes" aria-label="Permalink to &quot;2. 核心增强属性 (Attributes)&quot;">​</a></h2><p>这些属性让表单变得“智能”。</p><h3 id="_2-1-验证与限制" tabindex="-1">2.1 验证与限制 <a class="header-anchor" href="#_2-1-验证与限制" aria-label="Permalink to &quot;2.1 验证与限制&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">属性</th><th style="text-align:left;">描述</th><th style="text-align:left;">示例</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>required</code></strong></td><td style="text-align:left;"><strong>必填</strong>。为空时阻止提交并提示。</td><td style="text-align:left;"><code>&lt;input required&gt;</code></td></tr><tr><td style="text-align:left;"><strong><code>pattern</code></strong></td><td style="text-align:left;"><strong>正则验证</strong>。最强大的验证属性。</td><td style="text-align:left;"><code>&lt;input pattern=&quot;[0-9]{6}&quot;&gt;</code> (验证6位验证码)</td></tr><tr><td style="text-align:left;"><strong><code>min</code> / <code>max</code></strong></td><td style="text-align:left;">最小/最大值。适用于 <code>number</code>, <code>date</code>, <code>range</code>。</td><td style="text-align:left;"><code>&lt;input type=&quot;number&quot; min=&quot;1&quot; max=&quot;100&quot;&gt;</code></td></tr><tr><td style="text-align:left;"><strong><code>minlength</code> / <code>maxlength</code></strong></td><td style="text-align:left;">最小/最大字符长度。适用于 <code>text</code>, <code>password</code>。</td><td style="text-align:left;"><code>&lt;input maxlength=&quot;140&quot;&gt;</code></td></tr><tr><td style="text-align:left;"><strong><code>step</code></strong></td><td style="text-align:left;">数字间隔。</td><td style="text-align:left;"><code>&lt;input type=&quot;number&quot; step=&quot;0.5&quot;&gt;</code> (0, 0.5, 1.0...)</td></tr></tbody></table><h3 id="_2-2-用户体验优化" tabindex="-1">2.2 用户体验优化 <a class="header-anchor" href="#_2-2-用户体验优化" aria-label="Permalink to &quot;2.2 用户体验优化&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">属性</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>placeholder</code></strong></td><td style="text-align:left;"><strong>占位提示符</strong>。输入框为空时显示的灰色提示文字。</td></tr><tr><td style="text-align:left;"><strong><code>autofocus</code></strong></td><td style="text-align:left;"><strong>自动聚焦</strong>。页面加载后光标自动定位到该框（一个页面只能有一个）。</td></tr><tr><td style="text-align:left;"><strong><code>autocomplete</code></strong></td><td style="text-align:left;"><strong>自动完成</strong>。<code>on</code> (开启), <code>off</code> (关闭)。<br>建议用于敏感信息（验证码）关闭提示。</td></tr><tr><td style="text-align:left;"><strong><code>readonly</code></strong></td><td style="text-align:left;"><strong>只读</strong>。内容可见，可聚焦，可提交，但<strong>不可修改</strong>。</td></tr><tr><td style="text-align:left;"><strong><code>disabled</code></strong></td><td style="text-align:left;"><strong>禁用</strong>。变灰，不可聚焦，<strong>不会被提交</strong>。</td></tr><tr><td style="text-align:left;"><strong><code>multiple</code></strong></td><td style="text-align:left;"><strong>多选</strong>。适用于 <code>file</code> (上传多图) 和 <code>email</code> (逗号分隔多个邮箱)。</td></tr></tbody></table><h2 id="_3-新增表单标签" tabindex="-1">3. 新增表单标签 <a class="header-anchor" href="#_3-新增表单标签" aria-label="Permalink to &quot;3. 新增表单标签&quot;">​</a></h2><h3 id="_3-1-datalist-原生自动补全" tabindex="-1">3.1 <code>&lt;datalist&gt;</code> (原生自动补全) <a class="header-anchor" href="#_3-1-datalist-原生自动补全" aria-label="Permalink to &quot;3.1 `&lt;datalist&gt;` (原生自动补全)&quot;">​</a></h3><p>给输入框提供一个“预设推荐列表”，但用户依然可以输入列表以外的内容。</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">label</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;浏览器：&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">label</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">input</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> list</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;browsers&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;browser&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">datalist</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> id</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;browsers&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">option</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> value</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Chrome&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">option</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> value</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Firefox&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">option</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> value</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Safari&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">datalist</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><h3 id="_3-2-progress-和-meter" tabindex="-1">3.2 <code>&lt;progress&gt;</code> 和 <code>&lt;meter&gt;</code> <a class="header-anchor" href="#_3-2-progress-和-meter" aria-label="Permalink to &quot;3.2 `&lt;progress&gt;` 和 `&lt;meter&gt;`&quot;">​</a></h3><ul><li><strong><code>&lt;progress&gt;</code></strong>: 进度条（任务完成度）。<div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">progress</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> value</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;70&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> max</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;100&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">progress</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div></li><li><strong><code>&lt;meter&gt;</code></strong>: 刻度尺（如磁盘容量、温度）。有红黄绿颜色变化。<div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">meter</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> value</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;80&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> min</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;0&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> max</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;100&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> low</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;30&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> high</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;60&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">meter</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div></li></ul><h2 id="_4-常见问题-faq-与-避坑指南" tabindex="-1">4. 常见问题 (FAQ) 与 避坑指南 <a class="header-anchor" href="#_4-常见问题-faq-与-避坑指南" aria-label="Permalink to &quot;4. 常见问题 (FAQ) 与 避坑指南&quot;">​</a></h2><h3 id="_4-1-为什么移动端键盘不弹数字键盘" tabindex="-1">4.1 为什么移动端键盘不弹数字键盘？ <a class="header-anchor" href="#_4-1-为什么移动端键盘不弹数字键盘" aria-label="Permalink to &quot;4.1 为什么移动端键盘不弹数字键盘？&quot;">​</a></h3><p><strong>原因</strong>: 仅仅写 <code>type=&quot;number&quot;</code> 在某些 iOS 版本上可能无效。</p><p><strong>解法</strong>: 使用 <code>pattern</code> 强制指定。</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">input</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;text&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> pattern</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;[0-9]*&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> inputmode</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;numeric&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p><em>注：<code>inputmode</code> 是较新的属性，专门控制键盘类型。</em></p><h3 id="_4-2-如何修改-placeholder-的颜色" tabindex="-1">4.2 如何修改 <code>placeholder</code> 的颜色？ <a class="header-anchor" href="#_4-2-如何修改-placeholder-的颜色" aria-label="Permalink to &quot;4.2 如何修改 `placeholder` 的颜色？&quot;">​</a></h3><p>需要使用 CSS 伪元素（浏览器兼容性写法）。</p><div class="language-css vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">input</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">::placeholder</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">color</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">red</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; }</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">input</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">::-webkit-input-placeholder</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">color</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">red</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; } </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* Chrome/Safari */</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">input</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">::-moz-placeholder</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">color</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">red</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; } </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* Firefox */</span></span></code></pre></div><h3 id="_4-3-autocomplete-off-失效了" tabindex="-1">4.3 <code>autocomplete=&quot;off&quot;</code> 失效了？ <a class="header-anchor" href="#_4-3-autocomplete-off-失效了" aria-label="Permalink to &quot;4.3 `autocomplete=&quot;off&quot;` 失效了？&quot;">​</a></h3><p>现代浏览器（尤其是 Chrome）为了帮用户记密码，有时会忽略 <code>off</code> 设置。</p><p><strong>解法</strong>: 给 <code>name</code> 或 <code>id</code> 起个随机怪异的名字，或者在 <code>type=&quot;password&quot;</code> 上方放一个隐藏的 input 迷惑浏览器。</p><h3 id="_4-4-原生验证提示框太丑-怎么改" tabindex="-1">4.4 原生验证提示框太丑，怎么改？ <a class="header-anchor" href="#_4-4-原生验证提示框太丑-怎么改" aria-label="Permalink to &quot;4.4 原生验证提示框太丑，怎么改？&quot;">​</a></h3><p>浏览器的默认验证气泡（如“请填写此字段”）样式无法修改。 <strong>解法</strong>:</p><ol><li>禁用原生验证：<code>&lt;form novalidate&gt;</code>.</li><li>使用 JS 监听 <code>submit</code> 事件，手动检查数据并显示自定义样式的 Error Tips。</li><li>利用 CSS <code>:valid</code> 和 <code>:invalid</code> 伪类做样式反馈（变红/变绿）。</li></ol><h3 id="_4-5-readonly-和-disabled-的核心区别" tabindex="-1">4.5 <code>readonly</code> 和 <code>disabled</code> 的核心区别？ <a class="header-anchor" href="#_4-5-readonly-和-disabled-的核心区别" aria-label="Permalink to &quot;4.5 `readonly` 和 `disabled` 的核心区别？&quot;">​</a></h3><p><strong>面试必问</strong>。</p><ul><li><strong><code>readonly</code> (只读)</strong>: 数据<strong>会</strong>随表单一起提交到后端。</li><li><strong><code>disabled</code> (禁用)</strong>: 数据<strong>不会</strong>被提交。后端收不到这个字段。</li></ul><h3 id="_4-6-为什么-input-type-date-在-pc-端样式很难看" tabindex="-1">4.6 为什么 <code>&lt;input type=&quot;date&quot;&gt;</code> 在 PC 端样式很难看？ <a class="header-anchor" href="#_4-6-为什么-input-type-date-在-pc-端样式很难看" aria-label="Permalink to &quot;4.6 为什么 `&lt;input type=&quot;date&quot;&gt;` 在 PC 端样式很难看？&quot;">​</a></h3><p><strong>现状</strong>: 原生日期选择器在 Chrome PC 端样式非常简陋，且无法通过 CSS 定制。在 Safari/Firefox 上长得还不一样。</p><p><strong>解法</strong>: 商业项目中通常<strong>不使用原生 date</strong>，而是使用 JS 组件库（如 Flatpickr, Ant Design DatePicker）来保证 UI 一致性。但在<strong>移动端</strong>，强烈建议使用原生 <code>date</code>，因为能唤起系统级的原生滚轮，体验最好。</p><h3 id="_4-7-点击按钮没有反应-或者自动刷新页面了" tabindex="-1">4.7 点击按钮没有反应，或者自动刷新页面了？ <a class="header-anchor" href="#_4-7-点击按钮没有反应-或者自动刷新页面了" aria-label="Permalink to &quot;4.7 点击按钮没有反应，或者自动刷新页面了？&quot;">​</a></h3><p><strong>原因</strong>: <code>&lt;button&gt;</code> 默认的 <code>type</code> 是 <code>submit</code>。放在 <code>&lt;form&gt;</code> 里点击会自动提交刷新。</p><p><strong>解法</strong>: 如果只是想触发 JS 逻辑，请显式声明类型：</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">button</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;button&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> onclick</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">...</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;普通按钮&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">button</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div>',42)])])}const c=s(l,[["render",n]]);export{g as __pageData,c as default};
